#[derive(Debug, Clone, Copy)]
pub enum BinaryOp {
    // Comparison
    Eq,      // =
    Ne,      // != or <>
    Lt,      // <
    Le,      // <=
    Gt,      // >
    Ge,      // >=

    // Logical
    And,     // AND
    Or,      // OR

    // Arithmetic
    Add,     // +
    Sub,     // -
    Mul,     // *
    Div,     // /
    Mod,     // %

    // String
    Concat,  // || (PostgreSQL) or CONCAT() (MySQL)

    // Bitwise
    BitAnd,  // &
    BitOr,   // |
    BitXor,  // ^
}
```

