#[sqlmodel(skip_update)]           // Don't include in UPDATE
```

### Parsed Data Structures
```rust
struct ModelDef {
    name: Ident,
    table_name: String,
    table_alias: Option<String>,
    fields: Vec<FieldDef>,
    generics: Generics,
}

struct FieldDef {
    name: Ident,
    column_name: String,
    ty: Type,
    sql_type: Option<String>,
    nullable: bool,
    primary_key: bool,
    auto_increment: bool,
